pub trait FrfProducer: Send + Sized {
    type Item;
    type Iter: Iterator<Item = Self::Item>;

    fn len(&self) -> usize;
    fn is_empty(&self) -> bool {
        self.len() == 0
    }
    fn split_at(self, index: usize) -> (Self, Self);
    fn into_iter(self) -> Self::Iter;

    /// Aligns chunk boundaries to prevent false sharing (e.g. 64-byte cache lines)
    fn align_chunk(&self, chunk: usize) -> usize {
        chunk
    }
}

/// Approach (A) small-N fast path. When the producer has fewer than
/// `K * ELEMENTS_PER_WORKER` items, dispatch to fewer workers so each one
/// sees enough work to amortize the wake-up cost.
///
/// Heuristic:
///   * `total <= k`: one element per worker (preserves the L<=K fast path
///     where every worker has exactly one item — no false-sharing inside a
///     chunk, minimal wakes for maximum parallelism in the smallest regime).
///   * `k < total < k * ELEMENTS_PER_WORKER`: target ~ELEMENTS_PER_WORKER
///     elements per worker so each chunk is large enough to amortize the
///     park/unpark cost. 32 was picked empirically for stride-24 K=8 on
///     Apple Silicon: it lands L=16 K=8 at k_eff=2 (one helper, 8 elems
///     each), L=32 K=8 at k_eff=2 (16 elems each), and L=64 K=8 at k_eff=2
///     (32 elems each) — all comfortably inside rayon's medians. Tuning
///     down to 16 still wins L=16 / L=32 but loses L=64 because the four
///     wakes there cross rayon's deque-amortized dispatch cost.
///   * `total >= k * ELEMENTS_PER_WORKER`: full K — work is large enough
///     that wake-up cost is amortized over real per-worker work.
///
/// The L=16/L=32 K=8 stride-24 regression sits in the middle case: pre-fix
/// each of 8 workers got 2-4 items and paid the full park/unpark wake. After
/// fix only 2 workers participate at L=16/32/64, with the helper getting
/// proportionally more work as L grows.
///
/// Note `clamp(2, k)`: once we've decided to parallelize at all (`total > k`)
/// we never collapse back to k_eff=1, since the dispatch fast-path at the
/// callsite already handles that. Going from "tiny pool" to "no pool" is a
/// bigger semantic step than just shrinking the pool.
#[cfg(not(target_arch = "wasm32"))]
#[inline]
/// Serial cutoff for small bursty loads. Below this many elements the pool
/// dispatch cost (unpark + spin + atomic coordination, and under `get_pool`
/// lock contention a fresh `thread::scope` spawn) dominates the actual work, so
/// staying serial is strictly faster. Benchmarked never-regress floor: for
/// `total < 16` even heavy per-item work loses to dispatch; genuinely parallel
/// work only starts paying from `N ≈ 16` (see `benches/bench_small_bursty.rs`,
/// where cheap small loads ran 5–110× slower than serial under the old min-2
/// clamp). Tunable via `GNOSIS_FRF_SERIAL_CUTOFF`: raise it when per-item work
/// is known light (more bursty coordination tasks stay serial), lower it (min 2)
/// when per-item work is heavy enough to pay dispatch at smaller N.
#[cfg(not(target_arch = "wasm32"))]
pub(crate) fn serial_cutoff() -> usize {
    use std::sync::atomic::{AtomicUsize, Ordering};
    static CUTOFF: AtomicUsize = AtomicUsize::new(0);
    let cached = CUTOFF.load(Ordering::Relaxed);
    if cached != 0 {
        return cached;
    }
    let v = std::env::var("GNOSIS_FRF_SERIAL_CUTOFF")
        .ok()
        .and_then(|s| s.parse::<usize>().ok())
        .filter(|&n| n >= 2)
        .unwrap_or(16);
    CUTOFF.store(v, Ordering::Relaxed);
    v
}

#[cfg(not(target_arch = "wasm32"))]
fn compute_k_eff(total: usize, k: usize) -> usize {
    const ELEMENTS_PER_WORKER: usize = 32;
    if total <= 1 || k <= 1 {
        return 1;
    }
    // Small bursty loads: dispatch overhead dominates — stay serial.
    if total < serial_cutoff() {
        return 1;
    }
    if total <= k {
        return total;
    }
    let desired = total / ELEMENTS_PER_WORKER;
    desired.clamp(2, k)
}

#[cfg(target_arch = "wasm32")]
pub fn execute<P: FrfProducer, F>(producer: P, mut f: F)
where
    F: FnMut(P::Iter) + Sync + Send,
{
    f(producer.into_iter());
}

#[cfg(not(target_arch = "wasm32"))]
pub fn execute<P: FrfProducer, F>(producer: P, f: F)
where
    F: Fn(P::Iter) + Sync + Send,
{
    // Default path: gate k_eff on BATCH SIZE (`compute_k_eff`/`serial_cutoff`).
    execute_with_k_eff(producer, f, compute_k_eff);
}

/// Platform per-item coordination cost (ns), the dispatch side of the value-door
/// crossover. Calibrated once per platform; overridable via `GNOSIS_FRF_DISPATCH_NS`.
/// This is the per-item unpark/spin/atomic cost that `bench_small_bursty` exposed
/// as the real (per-item, N-scaling) overhead — NOT a fixed constant.
#[cfg(not(target_arch = "wasm32"))]
pub fn per_item_dispatch_ns() -> u64 {
    use std::sync::atomic::{AtomicU64, Ordering};
    static NS: AtomicU64 = AtomicU64::new(0);
    let cached = NS.load(Ordering::Relaxed);
    if cached != 0 {
        return cached;
    }
    // Default 100ns/item: calibrated so cheap (~1ns) work stays laminar (RED) and
    // genuinely heavy work opens the door (GREEN). See benches/bench_certified_gate.rs.
    let v = std::env::var("GNOSIS_FRF_DISPATCH_NS")
        .ok()
        .and_then(|s| s.parse::<u64>().ok())
        .filter(|&n| n > 0)
        .unwrap_or(100);
    NS.store(v, Ordering::Relaxed);
    v
}

/// CERTIFIED cost-aware path: gate k_eff on the value-door crossover using a
/// per-item work cost that the admission CERT attests (`value_door::
/// cost_aware_k_eff_certified`), not on batch size. Cheap work stays laminar
/// (serial) at every N — dodging the cheap-large over-dispatch the size cutoff
/// still pays; heavy work opens the door. Additive: does NOT change `execute`.
///
/// `certified_per_item_work_ns` comes from the admission cert (FOIL theorem-ID /
/// loser-observation cost class). Lean: `Gnosis.ValueDoorStoplight.
/// certified_never_yellow` — a cert in hand is always RED/GREEN, never a probe.
#[cfg(not(target_arch = "wasm32"))]
pub fn execute_with_certified_cost<P: FrfProducer, F>(
    producer: P,
    f: F,
    certified_per_item_work_ns: u64,
) where
    F: Fn(P::Iter) + Sync + Send,
{
    let dispatch = per_item_dispatch_ns();
    execute_with_k_eff(producer, f, move |total, k| {
        crate::value_door::cost_aware_k_eff_certified(
            total,
            k,
            certified_per_item_work_ns,
            dispatch,
        )
    });
}

/// Shared dispatch core: decide `k_eff` via `k_eff_fn`, then split + fan out.
/// Both the size-gated `execute` and the cost-gated `execute_with_certified_cost`
/// route through here so the only difference is the gate, never the dispatch.
#[cfg(not(target_arch = "wasm32"))]
fn execute_with_k_eff<P: FrfProducer, F, G>(producer: P, f: F, k_eff_fn: G)
where
    F: Fn(P::Iter) + Sync + Send,
    G: Fn(usize, usize) -> usize,
{
    if crate::pool::is_in_pool() {
        f(producer.into_iter());
        return;
    }
    if let Some(pool) = crate::pool::get_pool() {
        let k = pool.k;
        if k <= 1 || producer.len() <= 1 {
            f(producer.into_iter());
            return;
        }

        let total = producer.len();
        let k_eff = k_eff_fn(total, k);
        if k_eff <= 1 {
            f(producer.into_iter());
            return;
        }

        let mut producers: Vec<Option<P>> = (0..k_eff).map(|_| None).collect();
        let mut rem = producer;

        for (i, slot) in producers.iter_mut().enumerate().take(k_eff - 1) {
            let total = rem.len();
            let mut chunk = total.div_ceil(k_eff - i);
            chunk = rem.align_chunk(chunk);
            let limit = std::cmp::min(chunk, total);
            let (left, right) = rem.split_at(limit);
            *slot = Some(left);
            rem = right;
        }
        producers[k_eff - 1] = Some(rem);

        let ptr_val = producers.as_mut_ptr() as usize;

        crate::pool::execute_with_pool_k_eff(&pool, k_eff, &|index| {
            let p = unsafe { (*(ptr_val as *mut Option<P>).add(index)).take().unwrap() };
            f(p.into_iter());
        });
    } else {
        // No pool available (lock contention): the fallback spawns fresh
        // threads. Small bursty loads stay serial rather than pay a spawn.
        if producer.len() < serial_cutoff() {
            f(producer.into_iter());
            return;
        }
        let threads = std::thread::available_parallelism()
            .map(|n| n.get())
            .unwrap_or(1);
        execute_k(producer, &f, threads);
    }
}

#[cfg(not(target_arch = "wasm32"))]
fn execute_k<P: FrfProducer, F>(producer: P, f: &F, k: usize)
where
    F: Fn(P::Iter) + Sync + Send,
{
    if k <= 1 || producer.len() <= 1 {
        f(producer.into_iter());
        return;
    }
    let total = producer.len();
    let mut chunk = total.div_ceil(k);
    chunk = producer.align_chunk(chunk);
    let (left, right) = producer.split_at(std::cmp::min(chunk, total));

    std::thread::scope(|s| {
        s.spawn(move || {
            f(left.into_iter());
        });
        execute_k(right, f, k - 1);
    });
}

#[cfg(target_arch = "wasm32")]
pub fn execute_reduce<P: FrfProducer, ID, OP>(producer: P, identity: ID, op: OP) -> P::Item
where
    ID: Fn() -> P::Item + Sync + Send,
    OP: Fn(P::Item, P::Item) -> P::Item + Sync + Send,
{
    producer.into_iter().fold(identity(), op)
}

#[cfg(not(target_arch = "wasm32"))]
pub fn execute_reduce<P: FrfProducer, ID, OP>(producer: P, identity: ID, op: OP) -> P::Item
where
    ID: Fn() -> P::Item + Sync + Send,
    OP: Fn(P::Item, P::Item) -> P::Item + Sync + Send,
    P::Item: Send,
{
    if crate::pool::is_in_pool() {
        return producer.into_iter().fold(identity(), op);
    }
    if let Some(pool) = crate::pool::get_pool() {
        let k = pool.k;
        if k <= 1 || producer.len() <= 1 {
            return producer.into_iter().fold(identity(), op);
        }

        let total = producer.len();
        let k_eff = compute_k_eff(total, k);
        if k_eff <= 1 {
            return producer.into_iter().fold(identity(), op);
        }

        let mut producers: Vec<Option<P>> = (0..k_eff).map(|_| None).collect();
        let mut rem = producer;
        for (i, slot) in producers.iter_mut().enumerate().take(k_eff - 1) {
            let total = rem.len();
            let mut chunk = total.div_ceil(k_eff - i);
            chunk = rem.align_chunk(chunk);
            let limit = std::cmp::min(chunk, total);
            let (left, right) = rem.split_at(limit);
            *slot = Some(left);
            rem = right;
        }
        producers[k_eff - 1] = Some(rem);

        let ptr_val = producers.as_mut_ptr() as usize;

        // Allocate results array (only k_eff slots — only those workers run).
        let mut results: Vec<Option<P::Item>> = (0..k_eff).map(|_| None).collect();
        let res_ptr_val = results.as_mut_ptr() as usize;

        crate::pool::execute_with_pool_k_eff(&pool, k_eff, &|index| {
            let p = unsafe { (*(ptr_val as *mut Option<P>).add(index)).take().unwrap() };
            let val = p.into_iter().fold(identity(), &op);
            unsafe {
                *(res_ptr_val as *mut Option<P::Item>).add(index) = Some(val);
            }
        });

        results.into_iter().map(|x| x.unwrap()).reduce(op).unwrap()
    } else {
        let threads = std::thread::available_parallelism()
            .map(|n| n.get())
            .unwrap_or(1);
        execute_reduce_k(producer, &identity, &op, threads)
    }
}

#[cfg(not(target_arch = "wasm32"))]
fn execute_reduce_k<P: FrfProducer, ID, OP>(
    producer: P,
    identity: &ID,
    op: &OP,
    k: usize,
) -> P::Item
where
    ID: Fn() -> P::Item + Sync + Send,
    OP: Fn(P::Item, P::Item) -> P::Item + Sync + Send,
    P::Item: Send,
{
    if k <= 1 || producer.len() <= 1 {
        return producer.into_iter().fold(identity(), op);
    }
    let total = producer.len();
    let mut chunk = total.div_ceil(k);
    chunk = producer.align_chunk(chunk);
    let (left, right) = producer.split_at(std::cmp::min(chunk, total));

    std::thread::scope(|s| {
        let handle = s.spawn(move || left.into_iter().fold(identity(), op));
        let right_res = execute_reduce_k(right, identity, op, k - 1);
        let left_res = handle.join().unwrap();
        op(left_res, right_res)
    })
}

#[cfg(target_arch = "wasm32")]
pub fn execute_fold_reduce<P: FrfProducer, B, INIT, FOLD, REDUCE>(
    producer: P,
    init: INIT,
    fold: FOLD,
    _reduce: REDUCE,
) -> B
where
    B: Send,
    INIT: Fn() -> B + Sync + Send,
    FOLD: Fn(B, P::Item) -> B + Sync + Send,
    REDUCE: Fn(B, B) -> B + Sync + Send,
{
    producer.into_iter().fold(init(), fold)
}

#[cfg(not(target_arch = "wasm32"))]
pub fn execute_fold_reduce<P: FrfProducer, B, INIT, FOLD, REDUCE>(
    producer: P,
    init: INIT,
    fold: FOLD,
    reduce: REDUCE,
) -> B
where
    B: Send,
    P::Item: Send,
    INIT: Fn() -> B + Sync + Send,
    FOLD: Fn(B, P::Item) -> B + Sync + Send,
    REDUCE: Fn(B, B) -> B + Sync + Send,
{
    if crate::pool::is_in_pool() {
        return producer.into_iter().fold(init(), fold);
    }
    if let Some(pool) = crate::pool::get_pool() {
        let k = pool.k;
        if k <= 1 || producer.len() <= 1 {
            return producer.into_iter().fold(init(), fold);
        }

        let total = producer.len();
        let k_eff = compute_k_eff(total, k);
        if k_eff <= 1 {
            return producer.into_iter().fold(init(), fold);
        }

        let mut producers: Vec<Option<P>> = (0..k_eff).map(|_| None).collect();
        let mut rem = producer;
        for (i, slot) in producers.iter_mut().enumerate().take(k_eff - 1) {
            let total = rem.len();
            let mut chunk = total.div_ceil(k_eff - i);
            chunk = rem.align_chunk(chunk);
            let limit = std::cmp::min(chunk, total);
            let (left, right) = rem.split_at(limit);
            *slot = Some(left);
            rem = right;
        }
        producers[k_eff - 1] = Some(rem);

        let ptr_val = producers.as_mut_ptr() as usize;

        let mut results: Vec<Option<B>> = (0..k_eff).map(|_| None).collect();
        let res_ptr_val = results.as_mut_ptr() as usize;

        crate::pool::execute_with_pool_k_eff(&pool, k_eff, &|index| {
            let p = unsafe { (*(ptr_val as *mut Option<P>).add(index)).take().unwrap() };
            let val = p.into_iter().fold(init(), &fold);
            unsafe {
                *(res_ptr_val as *mut Option<B>).add(index) = Some(val);
            }
        });

        results
            .into_iter()
            .map(|x| x.unwrap())
            .reduce(reduce)
            .unwrap()
    } else {
        let threads = std::thread::available_parallelism()
            .map(|n| n.get())
            .unwrap_or(1);
        execute_fold_reduce_k(producer, &init, &fold, &reduce, threads)
    }
}

#[cfg(not(target_arch = "wasm32"))]
fn execute_fold_reduce_k<P: FrfProducer, B, INIT, FOLD, REDUCE>(
    producer: P,
    init: &INIT,
    fold: &FOLD,
    reduce: &REDUCE,
    k: usize,
) -> B
where
    B: Send,
    P::Item: Send,
    INIT: Fn() -> B + Sync + Send,
    FOLD: Fn(B, P::Item) -> B + Sync + Send,
    REDUCE: Fn(B, B) -> B + Sync + Send,
{
    if k <= 1 || producer.len() <= 1 {
        return producer.into_iter().fold(init(), fold);
    }
    let total = producer.len();
    let mut chunk = total.div_ceil(k);
    chunk = producer.align_chunk(chunk);
    let (left, right) = producer.split_at(std::cmp::min(chunk, total));

    std::thread::scope(|s| {
        let handle = s.spawn(move || left.into_iter().fold(init(), fold));
        let right_res = execute_fold_reduce_k(right, init, fold, reduce, k - 1);
        let left_res = handle.join().unwrap();
        reduce(left_res, right_res)
    })
}

// -----------------------------------------------------------------------------
// Sub-Chunking with Cooperative Yielding
//
// Split the producer into `M >= K` coarse-grained sub-chunks and distribute
// them across pool workers through a single relaxed atomic `fetch_add`.
// Each worker drains chunks until the counter is exhausted, so stragglers on
// one chunk do not stall the rest of the pool. This restores load balancing
// for tail-latency-heavy workloads without the per-item cost of work-stealing
// deques.
//
// Within-chunk stealing (the "two-level" scheduler):
//
// At very-unbalanced 100k-1M scale, even M=K*2048 sub-chunks can leave one
// worker stuck in a single sub-chunk that takes 100x longer than its peers.
// rayon handles this with deque-based mid-flight subdivision; FRF does it by
// splitting each top-level sub-chunk into M2 mini-batches lazily, the moment
// a worker picks the chunk up. The owning worker drains its mini-batches via
// a per-chunk relaxed `fetch_add`, but other workers (after the central
// counter exhausts) can scan peer chunks and `fetch_add`-steal one or more
// mini-batches.
//
// `STEAL_MIN_LEN` gates two-level: chunks below the threshold skip mini-
// batching entirely and run as one shot. This keeps the small-N benches
// (stride24 L=8/16/32/64) on the no-overhead path — no allocation, no
// extra atomic, identical to the pre-stealing behavior.
//
// Stealing is opt-in per execution path:
//   * `execute_sub_chunked` (for_each)             — yes
//   * `execute_reduce_sub_chunked`                 — yes (associative reduce, partials may be combined in any order)
//   * `execute_fold_reduce_sub_chunked`            — yes (same)
//   * `execute_collect_sub_chunked`                — no (input-order requirement; mini-batch flatten is doable but adds bookkeeping; deferred)
// -----------------------------------------------------------------------------

/// Minimum top-level sub-chunk length (in items) for which mini-batching kicks
/// in. Below this, the chunk runs as a single iterator pass and stealing has
/// nothing to grab from it.
///
/// Tuning rationale: the 1M auto-M case (chunks ~61 items) benefited 4x from
/// mini-batching because the bench's per-item cost is high and the heavy tail
/// concentrates inside individual chunks — mini-batches let other workers
/// drain the tail in parallel. The 100k auto-M case (chunks ~64 items, same
/// regime) regressed because the per-chunk mini-batch overhead (split + 8x
/// allocation + atomic cursor) is a larger fraction of the shorter total
/// runtime. The 10k tiny_unbalanced_auto (chunks ~64 items) regressed
/// dramatically (2ms → 9ms) for the same reason.
///
/// `STEAL_MIN_LEN` set to 96: just below the auto-M chunk size on common
/// large-N shapes, so the auto path can mini-batch only after the chunk has
/// enough mass to amortize the extra bookkeeping. Larger N configurations that
/// end up with fatter chunks (low
/// explicit `M`, high `N`) still trigger stealing — that's the regime where
/// the heavy-tail-stuck-in-one-chunk failure mode lives. Concretely:
///   * `with_sub_chunks(64)` at N=1M → chunks ~15_625 items → mini-batched
///   * `with_sub_chunks_auto()` at N=1M → chunks ~128 items → mini-batched
///
/// The auto path's coarseness is now the cost of zero-overhead small-N. If
/// callers hit the heavy-tail path they should either use a small explicit
/// `sub_chunks` or wait for a follow-up "auto picks coarser M when stealing
/// is enabled" patch.
#[allow(dead_code)]
const STEAL_MIN_LEN: usize = 96;

/// Mini-batches per top-level chunk. The chunk owner splits its chunk into
/// this many mini-batches. Higher M2 gives finer-grained stealing but pays
/// more split overhead and atomic-counter contention. M2=8 is a Triad-friendly
/// default — enough granularity that an idle worker can steal half a chunk
/// without paying per-item overhead.
#[allow(dead_code)]
const STEAL_MINI_BATCHES: usize = 8;

#[cfg(test)]
#[derive(Clone, Copy, Debug, Eq, PartialEq)]
struct MiniBatchAdmission {
    chunk_len: usize,
    required_len: usize,
    covered_mass: usize,
    residual_mass: usize,
    admitted: bool,
}

#[inline(always)]
#[cfg(test)]
fn assess_mini_batch_admission(producer_len: usize, sub_chunks: usize) -> MiniBatchAdmission {
    let effective_chunks = sub_chunks.max(1);
    let chunk_len = producer_len.div_ceil(effective_chunks);
    let residual_mass = STEAL_MIN_LEN.saturating_sub(chunk_len);

    MiniBatchAdmission {
        chunk_len,
        required_len: STEAL_MIN_LEN,
        covered_mass: chunk_len.min(STEAL_MIN_LEN),
        residual_mass,
        admitted: residual_mass == 0,
    }
}

#[cfg(not(target_arch = "wasm32"))]
struct StealCell<P> {
    /// Mini-batches for this top-level chunk. Indexed by mini-batch idx.
    /// The owning worker populates and `take()`s in cursor order; idle
    /// workers `fetch_add` the cursor and `take()` the resulting slot.
    /// Each slot is independently `take()`-once via the cursor protocol;
    /// no two workers ever see the same slot index.
    slots: std::sync::atomic::AtomicPtr<()>,
    /// Number of mini-batches actually populated. 0 means "owner has not
    /// yet split — do not attempt to steal from this chunk." Set by the
    /// owner via release-store after slots are populated; observed by
    /// stealers via acquire-load.
    populated: std::sync::atomic::AtomicUsize,
    /// Next mini-batch index to claim. Owner and stealers race on this
    /// via `fetch_add`. When `cursor >= populated`, the chunk is drained.
    cursor: std::sync::atomic::AtomicUsize,
    _marker: std::marker::PhantomData<P>,
}

// SAFETY: StealCell holds a raw pointer to UnsafeCell<Option<P>> slots.
// The slots are accessed only via the cursor protocol (each index taken
// at most once) and only from worker threads spawned by the pool, so as
// long as P: Send the cells can be shared.
#[cfg(not(target_arch = "wasm32"))]
unsafe impl<P: Send> Sync for StealCell<P> {}

#[cfg(not(target_arch = "wasm32"))]
impl<P> StealCell<P> {
    const fn new() -> Self {
        Self {
            slots: std::sync::atomic::AtomicPtr::new(std::ptr::null_mut()),
            populated: std::sync::atomic::AtomicUsize::new(0),
            cursor: std::sync::atomic::AtomicUsize::new(0),
            _marker: std::marker::PhantomData,
        }
    }
}

/// Split a top-level chunk producer into up to `m2` mini-batches.
/// Returns the populated `Vec<Option<P>>`. The vector length equals the
/// number of mini-batches actually produced — for tiny producers we may
/// emit fewer than `m2` slots.
#[cfg(not(target_arch = "wasm32"))]
fn split_into_mini_batches<P: FrfProducer>(producer: P, m2: usize) -> Vec<Option<P>> {
    if m2 <= 1 {
        return vec![Some(producer)];
    }
    let total = producer.len();
    if total == 0 {
        return vec![Some(producer)];
    }
    let actual_m2 = std::cmp::min(m2, total);
    let mut out: Vec<Option<P>> = (0..actual_m2).map(|_| None).collect();
    let mut rem = producer;
    for (i, slot) in out.iter_mut().enumerate().take(actual_m2 - 1) {
        let total = rem.len();
        let chunk = total.div_ceil(actual_m2 - i);
        let limit = std::cmp::min(chunk, total);
        let (left, right) = rem.split_at(limit);
        *slot = Some(left);
        rem = right;
    }
    out[actual_m2 - 1] = Some(rem);
    out
}

/// Drain mini-batches from `cell`, calling `f` on each. Stops when the
/// cursor reaches `populated`. Used by both the chunk owner (after it
/// publishes) and stealers.
///
/// SAFETY: Caller must guarantee `cell.slots` points to a valid
/// `[UnsafeCell<Option<P>>; populated]`-shaped buffer that outlives this
/// call, and that `populated` has been observed via acquire-load.
#[cfg(not(target_arch = "wasm32"))]
unsafe fn drain_mini_batches<P, F>(cell: &StealCell<P>, f: &F)
where
    P: FrfProducer,
    F: Fn(P::Iter) + Sync + Send,
{
    let populated = cell.populated.load(std::sync::atomic::Ordering::Acquire);
    if populated == 0 {
        return;
    }
    let slots_ptr = cell.slots.load(std::sync::atomic::Ordering::Acquire)
        as *mut std::cell::UnsafeCell<Option<P>>;
    if slots_ptr.is_null() {
        return;
    }
    loop {
        let i = cell
            .cursor
            .fetch_add(1, std::sync::atomic::Ordering::Relaxed);
        if i >= populated {
            break;
        }
        let slot = unsafe { &*slots_ptr.add(i) };
        let p = unsafe { (*slot.get()).take() };
        if let Some(p) = p {
            f(p.into_iter());
        }
    }
}

/// Reduce variant of [`drain_mini_batches`]: folds each mini-batch into `acc`.
#[cfg(not(target_arch = "wasm32"))]
unsafe fn drain_mini_batches_reduce<P, B, FOLD>(cell: &StealCell<P>, mut acc: B, fold: &FOLD) -> B
where
    P: FrfProducer,
    FOLD: Fn(B, P::Item) -> B + Sync + Send,
{
    let populated = cell.populated.load(std::sync::atomic::Ordering::Acquire);
    if populated == 0 {
        return acc;
    }
    let slots_ptr = cell.slots.load(std::sync::atomic::Ordering::Acquire)
        as *mut std::cell::UnsafeCell<Option<P>>;
    if slots_ptr.is_null() {
        return acc;
    }
    loop {
        let i = cell
            .cursor
            .fetch_add(1, std::sync::atomic::Ordering::Relaxed);
        if i >= populated {
            break;
        }
        let slot = unsafe { &*slots_ptr.add(i) };
        let p = unsafe { (*slot.get()).take() };
        if let Some(p) = p {
            acc = p.into_iter().fold(acc, fold);
        }
    }
    acc
}

// -----------------------------------------------------------------------------
// Scope-based sub-chunk drivers.
//
// When the persistent pool is unavailable (nested parallelism, or the pool
// feature is disabled), we still want cooperative yielding. `thread::scope`
// spawns K workers on demand; they coordinate through a shared relaxed
// `AtomicUsize` exactly like the pool path. Spawn cost is paid once per
// call, so this is a drop-in fallback rather than a hot-path regression.
// -----------------------------------------------------------------------------

#[cfg(not(target_arch = "wasm32"))]
fn drain_sub_chunks<P: FrfProducer, F>(
    producers_ptr: usize,
    counter: &std::sync::atomic::AtomicUsize,
    m: usize,
    f: &F,
) where
    F: Fn(P::Iter) + Sync + Send,
{
    loop {
        let idx = counter.fetch_add(1, std::sync::atomic::Ordering::Relaxed);
        if idx >= m {
            break;
        }
        let p = unsafe {
            (*(producers_ptr as *mut Option<P>).add(idx))
                .take()
                .unwrap()
        };
        f(p.into_iter());
    }
}

#[cfg(not(target_arch = "wasm32"))]
fn execute_sub_chunked_scope<P, F>(producer: P, sub_chunks: usize, f: &F, k: usize)
where
    P: FrfProducer,
    F: Fn(P::Iter) + Sync + Send,
{
    if k <= 1 || producer.len() <= 1 {
        f(producer.into_iter());
        return;
    }
    let m = std::cmp::max(sub_chunks, k);
    let mut producers = split_into_sub_chunks(producer, m);
    let counter = std::sync::atomic::AtomicUsize::new(0);
    let ptr_val = producers.as_mut_ptr() as usize;

    std::thread::scope(|s| {
        let counter_ref = &counter;
        for _ in 0..k - 1 {
            s.spawn(move || drain_sub_chunks::<P, F>(ptr_val, counter_ref, m, f));
        }
        drain_sub_chunks::<P, F>(ptr_val, &counter, m, f);
    });
}

#[cfg(not(target_arch = "wasm32"))]
fn execute_reduce_sub_chunked_scope<P, ID, OP>(
    producer: P,
    sub_chunks: usize,
    identity: &ID,
    op: &OP,
    k: usize,
) -> P::Item
where
    P: FrfProducer,
    P::Item: Send,
    ID: Fn() -> P::Item + Sync + Send,
    OP: Fn(P::Item, P::Item) -> P::Item + Sync + Send,
{
    if k <= 1 || producer.len() <= 1 {
        return producer.into_iter().fold(identity(), op);
    }
    let m = std::cmp::max(sub_chunks, k);
    let mut producers = split_into_sub_chunks(producer, m);
    let counter = std::sync::atomic::AtomicUsize::new(0);
    let ptr_val = producers.as_mut_ptr() as usize;

    let partials: Vec<P::Item> = std::thread::scope(|s| {
        let counter_ref = &counter;
        let handles: Vec<_> = (0..k - 1)
            .map(|_| {
                s.spawn(move || {
                    let mut acc = identity();
                    loop {
                        let idx = counter_ref.fetch_add(1, std::sync::atomic::Ordering::Relaxed);
                        if idx >= m {
                            break;
                        }
                        let p = unsafe { (*(ptr_val as *mut Option<P>).add(idx)).take().unwrap() };
                        acc = p.into_iter().fold(acc, op);
                    }
                    acc
                })
            })
            .collect();

        let mut main_acc = identity();
        loop {
            let idx = counter.fetch_add(1, std::sync::atomic::Ordering::Relaxed);
            if idx >= m {
                break;
            }
            let p = unsafe { (*(ptr_val as *mut Option<P>).add(idx)).take().unwrap() };
            main_acc = p.into_iter().fold(main_acc, op);
        }

        let mut out = Vec::with_capacity(k);
        out.push(main_acc);
        for h in handles {
            out.push(h.join().unwrap());
        }
        out
    });

    partials.into_iter().reduce(op).unwrap_or_else(identity)
}

#[cfg(not(target_arch = "wasm32"))]
fn execute_fold_reduce_sub_chunked_scope<P, B, INIT, FOLD, REDUCE>(
    producer: P,
    sub_chunks: usize,
    init: &INIT,
    fold: &FOLD,
    reduce: &REDUCE,
    k: usize,
) -> B
where
    P: FrfProducer,
    P::Item: Send,
    B: Send,
    INIT: Fn() -> B + Sync + Send,
    FOLD: Fn(B, P::Item) -> B + Sync + Send,
    REDUCE: Fn(B, B) -> B + Sync + Send,
{
    if k <= 1 || producer.len() <= 1 {
        return producer.into_iter().fold(init(), fold);
    }
    let m = std::cmp::max(sub_chunks, k);
    let mut producers = split_into_sub_chunks(producer, m);
    let counter = std::sync::atomic::AtomicUsize::new(0);
    let ptr_val = producers.as_mut_ptr() as usize;

    let partials: Vec<B> = std::thread::scope(|s| {
        let counter_ref = &counter;
        let handles: Vec<_> = (0..k - 1)
            .map(|_| {
                s.spawn(move || {
                    let mut acc = init();
                    loop {
                        let idx = counter_ref.fetch_add(1, std::sync::atomic::Ordering::Relaxed);
                        if idx >= m {
                            break;
                        }
                        let p = unsafe { (*(ptr_val as *mut Option<P>).add(idx)).take().unwrap() };
                        acc = p.into_iter().fold(acc, fold);
                    }
                    acc
                })
            })
            .collect();

        let mut main_acc = init();
        loop {
            let idx = counter.fetch_add(1, std::sync::atomic::Ordering::Relaxed);
            if idx >= m {
                break;
            }
            let p = unsafe { (*(ptr_val as *mut Option<P>).add(idx)).take().unwrap() };
            main_acc = p.into_iter().fold(main_acc, fold);
        }

        let mut out = Vec::with_capacity(k);
        out.push(main_acc);
        for h in handles {
            out.push(h.join().unwrap());
        }
        out
    });

    partials.into_iter().reduce(reduce).unwrap_or_else(init)
}

#[cfg(not(target_arch = "wasm32"))]
fn execute_collect_sub_chunked_scope<P>(producer: P, sub_chunks: usize, k: usize) -> Vec<P::Item>
where
    P: FrfProducer,
    P::Item: Send,
{
    if k <= 1 || producer.len() <= 1 {
        return producer.into_iter().collect();
    }
    let m = std::cmp::max(sub_chunks, k);
    let mut producers = split_into_sub_chunks(producer, m);
    let mut chunk_results: Vec<Option<Vec<P::Item>>> = (0..m).map(|_| None).collect();
    let counter = std::sync::atomic::AtomicUsize::new(0);
    let prod_ptr = producers.as_mut_ptr() as usize;
    let res_ptr = chunk_results.as_mut_ptr() as usize;

    std::thread::scope(|s| {
        let counter_ref = &counter;
        for _ in 0..k - 1 {
            s.spawn(move || {
                loop {
                    let idx = counter_ref.fetch_add(1, std::sync::atomic::Ordering::Relaxed);
                    if idx >= m {
                        break;
                    }
                    let p = unsafe { (*(prod_ptr as *mut Option<P>).add(idx)).take().unwrap() };
                    let items: Vec<P::Item> = p.into_iter().collect();
                    unsafe {
                        *(res_ptr as *mut Option<Vec<P::Item>>).add(idx) = Some(items);
                    }
                }
            });
        }
        loop {
            let idx = counter.fetch_add(1, std::sync::atomic::Ordering::Relaxed);
            if idx >= m {
                break;
            }
            let p = unsafe { (*(prod_ptr as *mut Option<P>).add(idx)).take().unwrap() };
            let items: Vec<P::Item> = p.into_iter().collect();
            unsafe {
                *(res_ptr as *mut Option<Vec<P::Item>>).add(idx) = Some(items);
            }
        }
    });

    let mut out = Vec::new();
    for mut v in chunk_results.into_iter().flatten() {
        out.append(&mut v);
    }
    out
}

#[cfg(not(target_arch = "wasm32"))]
fn split_into_sub_chunks<P: FrfProducer>(producer: P, m: usize) -> Vec<Option<P>> {
    let mut producers: Vec<Option<P>> = (0..m).map(|_| None).collect();
    let mut rem = producer;
    for (i, slot) in producers.iter_mut().enumerate().take(m - 1) {
        let total = rem.len();
        let limit = if total == 0 {
            0
        } else {
            let mut chunk = total.div_ceil(m - i);
            chunk = rem.align_chunk(chunk);
            std::cmp::min(chunk, total)
        };
        let (left, right) = rem.split_at(limit);
        *slot = Some(left);
        rem = right;
    }
    producers[m - 1] = Some(rem);
    producers
}

#[cfg(not(target_arch = "wasm32"))]
#[allow(dead_code)]
struct ExecutionPermutation {
    order: Vec<usize>,
}

#[cfg(not(target_arch = "wasm32"))]
fn stable_execution_permutation_for_chunks<P: FrfProducer>(
    producers: &[Option<P>],
) -> ExecutionPermutation {
    let mut order: Vec<usize> = (0..producers.len()).collect();
    order.sort_by_key(|index| {
        (
            std::cmp::Reverse(producers[*index].as_ref().map_or(0, FrfProducer::len)),
            *index,
        )
    });
    ExecutionPermutation { order }
}

#[cfg(not(target_arch = "wasm32"))]
#[allow(dead_code)]
fn chunks_are_balanced<P: FrfProducer>(producers: &[Option<P>]) -> bool {
    let mut min_len = usize::MAX;
    let mut max_len = 0usize;

    for len in producers
        .iter()
        .filter_map(|producer| producer.as_ref().map(FrfProducer::len))
    {
        min_len = min_len.min(len);
        max_len = max_len.max(len);
    }

    max_len.saturating_sub(min_len) <= 1
}

#[cfg(target_arch = "wasm32")]
pub fn execute_sub_chunked<P: FrfProducer, F>(producer: P, _sub_chunks: usize, mut f: F)
where
    F: FnMut(P::Iter) + Sync + Send,
{
    f(producer.into_iter());
}

#[cfg(not(target_arch = "wasm32"))]
pub fn execute_sub_chunked<P: FrfProducer, F>(producer: P, sub_chunks: usize, f: F)
where
    F: Fn(P::Iter) + Sync + Send,
{
    if crate::pool::is_in_pool() {
        f(producer.into_iter());
        return;
    }
    if let Some(pool) = crate::pool::get_pool() {
        let k = pool.k;
        if k <= 1 || producer.len() <= 1 {
            f(producer.into_iter());
            return;
        }
        let m = std::cmp::max(sub_chunks, k);
        let mini_batch_enabled = producer.len().div_ceil(m) >= STEAL_MIN_LEN;
        let mut producers = split_into_sub_chunks(producer, m);

        if !mini_batch_enabled {
            let balanced_chunks = chunks_are_balanced(&producers);
            let permutation = if balanced_chunks {
                None
            } else {
                Some(stable_execution_permutation_for_chunks(&producers))
            };
            let counter = std::sync::atomic::AtomicUsize::new(0);
            let counter_ptr = &counter as *const std::sync::atomic::AtomicUsize as usize;
            let ptr_val = producers.as_mut_ptr() as usize;
            let order_ptr = permutation
                .as_ref()
                .map_or(std::ptr::null::<usize>() as usize, |p| {
                    p.order.as_ptr() as usize
                });

            crate::pool::execute_with_pool(&pool, &|_index| {
                loop {
                    let counter =
                        unsafe { &*(counter_ptr as *const std::sync::atomic::AtomicUsize) };
                    let slot = counter.fetch_add(1, std::sync::atomic::Ordering::Relaxed);
                    if slot >= m {
                        break;
                    }
                    let idx = if order_ptr == 0 {
                        slot
                    } else {
                        unsafe { *(order_ptr as *const usize).add(slot) }
                    };
                    let p = unsafe { (*(ptr_val as *mut Option<P>).add(idx)).take().unwrap() };
                    f(p.into_iter());
                }
            });
            drop(permutation);
            drop(producers);
            return;
        }

        // Per-chunk steal cells. Each cell starts with `populated=0`, signaling
        // "not yet split, do not steal." When a worker grabs chunk `idx` via
        // the central counter and decides to mini-batch (chunk len >= STEAL_MIN_LEN),
        // it splits `producers[idx]`, populates `cells[idx].slots`, then sets
        // `cells[idx].populated = m2` via release-store. From that point on
        // any worker can steal from it via `cells[idx].cursor`.
        let mut cells: Vec<StealCell<P>> = (0..m).map(|_| StealCell::new()).collect();
        // Backing storage for the mini-batches of each chunk. Allocated up
        // front so pointers stay stable. Only the chunks that actually get
        // mini-batched use their slot — the rest hold an empty Vec.
        let mut mini_storage: Vec<Vec<std::cell::UnsafeCell<Option<P>>>> =
            (0..m).map(|_| Vec::new()).collect();

        let counter = std::sync::atomic::AtomicUsize::new(0);
        let counter_ptr = &counter as *const std::sync::atomic::AtomicUsize as usize;
        let ptr_val = producers.as_mut_ptr() as usize;
        let cells_ptr = cells.as_mut_ptr() as usize;
        let mini_storage_ptr = mini_storage.as_mut_ptr() as usize;

        crate::pool::execute_with_pool(&pool, &|_index| {
            // Phase 1: grab chunks via the central counter. For each chunk, if
            // it's large enough, mini-batch it and drain the local cell. Other
            // workers may steal from this cell during the drain.
            loop {
                let counter = unsafe { &*(counter_ptr as *const std::sync::atomic::AtomicUsize) };
                let idx = counter.fetch_add(1, std::sync::atomic::Ordering::Relaxed);
                if idx >= m {
                    break;
                }
                let p_opt = unsafe { (*(ptr_val as *mut Option<P>).add(idx)).take() };
                let Some(p) = p_opt else {
                    continue;
                };
                let plen = p.len();
                if plen < STEAL_MIN_LEN {
                    // Small chunk: skip mini-batching overhead entirely.
                    f(p.into_iter());
                    continue;
                }
                // Large chunk: mini-batch and publish.
                let mini = split_into_mini_batches(p, STEAL_MINI_BATCHES);
                let m2 = mini.len();
                let storage: &mut Vec<std::cell::UnsafeCell<Option<P>>> = unsafe {
                    &mut *(mini_storage_ptr as *mut Vec<std::cell::UnsafeCell<Option<P>>>).add(idx)
                };
                storage.reserve_exact(m2);
                for opt in mini {
                    storage.push(std::cell::UnsafeCell::new(opt));
                }
                let cell: &StealCell<P> = unsafe { &*(cells_ptr as *const StealCell<P>).add(idx) };
                cell.slots.store(
                    storage.as_mut_ptr() as *mut (),
                    std::sync::atomic::Ordering::Release,
                );
                cell.populated
                    .store(m2, std::sync::atomic::Ordering::Release);
                // Drain (with peers possibly stealing).
                unsafe {
                    drain_mini_batches::<P, F>(cell, &f);
                }
            }

            // Phase 2: steal from peer cells until everything is drained.
            //
            // After the central counter is exhausted, every chunk has either
            // been picked up by some worker or already drained. We scan the
            // cells; for any with remaining mini-batches we help drain. The
            // central counter is now monotone-final, so the only remaining
            // work is whatever sits in cells with `cursor < populated`.
            //
            // Spin discipline: contention on a single hot cell's cursor is
            // worse than a few workers idling, so we make a full sweep,
            // count work, and if a sweep produces nothing we exit. The
            // chunks-still-being-published race is impossible at this point:
            // a worker that picked up chunk `idx` either skipped mini-batching
            // (small chunk, already done) or published `populated > 0` before
            // entering the drain. If we observe `populated == 0` here and
            // central >= m, that chunk was a small one — already drained.
            let central_ref = unsafe { &*(counter_ptr as *const std::sync::atomic::AtomicUsize) };
            // First wait for central counter to be exhausted before stealing.
            // Otherwise we steal from a chunk whose owner is about to drain
            // it, hammering the cursor unnecessarily.
            while central_ref.load(std::sync::atomic::Ordering::Relaxed) < m {
                // Try to steal in the meantime — owners may still be slow on
                // earlier chunks while the central counter is moving.
                let mut did_work = false;
                for j in 0..m {
                    let cell: &StealCell<P> =
                        unsafe { &*(cells_ptr as *const StealCell<P>).add(j) };
                    let populated = cell.populated.load(std::sync::atomic::Ordering::Acquire);
                    if populated == 0 {
                        continue;
                    }
                    let cursor = cell.cursor.load(std::sync::atomic::Ordering::Relaxed);
                    if cursor >= populated {
                        continue;
                    }
                    unsafe {
                        drain_mini_batches::<P, F>(cell, &f);
                    }
                    did_work = true;
                }
                if !did_work {
                    std::hint::spin_loop();
                }
            }
            // Central exhausted — final drain sweep until nothing left.
            loop {
                let mut did_work = false;
                for j in 0..m {
                    let cell: &StealCell<P> =
                        unsafe { &*(cells_ptr as *const StealCell<P>).add(j) };
                    let populated = cell.populated.load(std::sync::atomic::Ordering::Acquire);
                    if populated == 0 {
                        continue;
                    }
                    let cursor = cell.cursor.load(std::sync::atomic::Ordering::Relaxed);
                    if cursor >= populated {
                        continue;
                    }
                    unsafe {
                        drain_mini_batches::<P, F>(cell, &f);
                    }
                    did_work = true;
                }
                if !did_work {
                    break;
                }
            }
        });
        // Keep storage alive until all workers are done.
        drop(cells);
        drop(mini_storage);
        drop(producers);
    } else {
        let threads = std::thread::available_parallelism()
            .map(|n| n.get())
            .unwrap_or(1);
        execute_sub_chunked_scope(producer, sub_chunks, &f, threads);
    }
}

#[cfg(target_arch = "wasm32")]
pub fn execute_reduce_sub_chunked<P: FrfProducer, ID, OP>(
    producer: P,
    _sub_chunks: usize,
    identity: ID,
    op: OP,
) -> P::Item
where
    ID: Fn() -> P::Item + Sync + Send,
    OP: Fn(P::Item, P::Item) -> P::Item + Sync + Send,
{
    producer.into_iter().fold(identity(), op)
}

#[cfg(not(target_arch = "wasm32"))]
pub fn execute_reduce_sub_chunked<P: FrfProducer, ID, OP>(
    producer: P,
    sub_chunks: usize,
    identity: ID,
    op: OP,
) -> P::Item
where
    ID: Fn() -> P::Item + Sync + Send,
    OP: Fn(P::Item, P::Item) -> P::Item + Sync + Send,
    P::Item: Send,
{
    if crate::pool::is_in_pool() {
        return producer.into_iter().fold(identity(), op);
    }
    if let Some(pool) = crate::pool::get_pool() {
        let k = pool.k;
        if k <= 1 || producer.len() <= 1 {
            return producer.into_iter().fold(identity(), op);
        }
        let m = std::cmp::max(sub_chunks, k);
        let mini_batch_enabled = producer.len().div_ceil(m) >= STEAL_MIN_LEN;
        let mut producers = split_into_sub_chunks(producer, m);

        if !mini_batch_enabled {
            let balanced_chunks = chunks_are_balanced(&producers);
            let permutation = if balanced_chunks {
                None
            } else {
                Some(stable_execution_permutation_for_chunks(&producers))
            };
            let counter = std::sync::atomic::AtomicUsize::new(0);
            let counter_ptr = &counter as *const std::sync::atomic::AtomicUsize as usize;
            let ptr_val = producers.as_mut_ptr() as usize;
            let order_ptr = permutation
                .as_ref()
                .map_or(std::ptr::null::<usize>() as usize, |p| {
                    p.order.as_ptr() as usize
                });

            let mut results: Vec<Option<P::Item>> = (0..k).map(|_| None).collect();
            let res_ptr_val = results.as_mut_ptr() as usize;

            crate::pool::execute_with_pool(&pool, &|index| {
                let mut acc = identity();
                loop {
                    let counter =
                        unsafe { &*(counter_ptr as *const std::sync::atomic::AtomicUsize) };
                    let slot = counter.fetch_add(1, std::sync::atomic::Ordering::Relaxed);
                    if slot >= m {
                        break;
                    }
                    let idx = if order_ptr == 0 {
                        slot
                    } else {
                        unsafe { *(order_ptr as *const usize).add(slot) }
                    };
                    let p = unsafe { (*(ptr_val as *mut Option<P>).add(idx)).take().unwrap() };
                    acc = p.into_iter().fold(acc, &op);
                }
                unsafe {
                    *(res_ptr_val as *mut Option<P::Item>).add(index) = Some(acc);
                }
            });
            drop(permutation);
            drop(producers);

            return results
                .into_iter()
                .flatten()
                .reduce(op)
                .unwrap_or_else(identity);
        }

        let mut cells: Vec<StealCell<P>> = (0..m).map(|_| StealCell::new()).collect();
        let mut mini_storage: Vec<Vec<std::cell::UnsafeCell<Option<P>>>> =
            (0..m).map(|_| Vec::new()).collect();

        let counter = std::sync::atomic::AtomicUsize::new(0);
        let counter_ptr = &counter as *const std::sync::atomic::AtomicUsize as usize;
        let ptr_val = producers.as_mut_ptr() as usize;
        let cells_ptr = cells.as_mut_ptr() as usize;
        let mini_storage_ptr = mini_storage.as_mut_ptr() as usize;

        let mut results: Vec<Option<P::Item>> = (0..k).map(|_| None).collect();
        let res_ptr_val = results.as_mut_ptr() as usize;

        crate::pool::execute_with_pool(&pool, &|index| {
            let mut acc = identity();
            loop {
                let counter = unsafe { &*(counter_ptr as *const std::sync::atomic::AtomicUsize) };
                let idx = counter.fetch_add(1, std::sync::atomic::Ordering::Relaxed);
                if idx >= m {
                    break;
                }
                let p_opt = unsafe { (*(ptr_val as *mut Option<P>).add(idx)).take() };
                let Some(p) = p_opt else {
                    continue;
                };
                let plen = p.len();
                if plen < STEAL_MIN_LEN {
                    acc = p.into_iter().fold(acc, &op);
                    continue;
                }

                let mini = split_into_mini_batches(p, STEAL_MINI_BATCHES);
                let m2 = mini.len();
                let storage: &mut Vec<std::cell::UnsafeCell<Option<P>>> = unsafe {
                    &mut *(mini_storage_ptr as *mut Vec<std::cell::UnsafeCell<Option<P>>>).add(idx)
                };
                storage.reserve_exact(m2);
                for opt in mini {
                    storage.push(std::cell::UnsafeCell::new(opt));
                }
                let cell: &StealCell<P> = unsafe { &*(cells_ptr as *const StealCell<P>).add(idx) };
                cell.slots.store(
                    storage.as_mut_ptr() as *mut (),
                    std::sync::atomic::Ordering::Release,
                );
                cell.populated
                    .store(m2, std::sync::atomic::Ordering::Release);
                acc = unsafe { drain_mini_batches_reduce::<P, P::Item, OP>(cell, acc, &op) };
            }

            let central_ref = unsafe { &*(counter_ptr as *const std::sync::atomic::AtomicUsize) };
            while central_ref.load(std::sync::atomic::Ordering::Relaxed) < m {
                let mut did_work = false;
                for j in 0..m {
                    let cell: &StealCell<P> =
                        unsafe { &*(cells_ptr as *const StealCell<P>).add(j) };
                    let populated = cell.populated.load(std::sync::atomic::Ordering::Acquire);
                    if populated == 0 {
                        continue;
                    }
                    let cursor = cell.cursor.load(std::sync::atomic::Ordering::Relaxed);
                    if cursor >= populated {
                        continue;
                    }
                    acc = unsafe { drain_mini_batches_reduce::<P, P::Item, OP>(cell, acc, &op) };
                    did_work = true;
                }
                if !did_work {
                    std::hint::spin_loop();
                }
            }

            loop {
                let mut did_work = false;
                for j in 0..m {
                    let cell: &StealCell<P> =
                        unsafe { &*(cells_ptr as *const StealCell<P>).add(j) };
                    let populated = cell.populated.load(std::sync::atomic::Ordering::Acquire);
                    if populated == 0 {
                        continue;
                    }
                    let cursor = cell.cursor.load(std::sync::atomic::Ordering::Relaxed);
                    if cursor >= populated {
                        continue;
                    }
                    acc = unsafe { drain_mini_batches_reduce::<P, P::Item, OP>(cell, acc, &op) };
                    did_work = true;
                }
                if !did_work {
                    break;
                }
            }

            unsafe {
                *(res_ptr_val as *mut Option<P::Item>).add(index) = Some(acc);
            }
        });
        drop(cells);
        drop(mini_storage);
        drop(producers);

        results
            .into_iter()
            .flatten()
            .reduce(op)
            .unwrap_or_else(identity)
    } else {
        let threads = std::thread::available_parallelism()
            .map(|n| n.get())
            .unwrap_or(1);
        execute_reduce_sub_chunked_scope(producer, sub_chunks, &identity, &op, threads)
    }
}

/// Order-preserving collect under sub-chunked scheduling.
///
/// `execute_fold_reduce_sub_chunked` accumulates into per-worker partials, so
/// each worker's buffer is the concatenation of whichever chunks it happened
/// to draw — not input order. When the output must match the input sequence
/// (i.e. `collect`), we need per-chunk storage: every sub-chunk drops its
/// items into its own slot and the driver flattens slots in chunk index
/// order. Matches the static `execute_fold_reduce` collect semantics.
#[cfg(target_arch = "wasm32")]
pub fn execute_collect_sub_chunked<P>(producer: P, _sub_chunks: usize) -> Vec<P::Item>
where
    P: FrfProducer,
{
    producer.into_iter().collect()
}

#[cfg(not(target_arch = "wasm32"))]
pub fn execute_collect_sub_chunked<P>(producer: P, sub_chunks: usize) -> Vec<P::Item>
where
    P: FrfProducer,
    P::Item: Send,
{
    if crate::pool::is_in_pool() {
        return producer.into_iter().collect();
    }
    if let Some(pool) = crate::pool::get_pool() {
        let k = pool.k;
        if k <= 1 || producer.len() <= 1 {
            return producer.into_iter().collect();
        }
        let m = std::cmp::max(sub_chunks, k);
        let mut producers = split_into_sub_chunks(producer, m);
        let balanced_chunks = chunks_are_balanced(&producers);
        let permutation = if balanced_chunks {
            None
        } else {
            Some(stable_execution_permutation_for_chunks(&producers))
        };

        let mut chunk_results: Vec<Option<Vec<P::Item>>> = (0..m).map(|_| None).collect();

        let counter = std::sync::atomic::AtomicUsize::new(0);
        let counter_ptr = &counter as *const std::sync::atomic::AtomicUsize as usize;
        let prod_ptr = producers.as_mut_ptr() as usize;
        let res_ptr = chunk_results.as_mut_ptr() as usize;
        let order_ptr = permutation
            .as_ref()
            .map_or(std::ptr::null::<usize>() as usize, |p| {
                p.order.as_ptr() as usize
            });

        crate::pool::execute_with_pool(&pool, &|_index| {
            loop {
                let counter = unsafe { &*(counter_ptr as *const std::sync::atomic::AtomicUsize) };
                let slot = counter.fetch_add(1, std::sync::atomic::Ordering::Relaxed);
                if slot >= m {
                    break;
                }
                let idx = if order_ptr == 0 {
                    slot
                } else {
                    unsafe { *(order_ptr as *const usize).add(slot) }
                };
                let p = unsafe { (*(prod_ptr as *mut Option<P>).add(idx)).take().unwrap() };
                let items: Vec<P::Item> = p.into_iter().collect();
                unsafe {
                    *(res_ptr as *mut Option<Vec<P::Item>>).add(idx) = Some(items);
                }
            }
        });
        drop(permutation);

        let mut out: Vec<P::Item> = Vec::new();
        for mut v in chunk_results.into_iter().flatten() {
            out.append(&mut v);
        }
        out
    } else {
        let threads = std::thread::available_parallelism()
            .map(|n| n.get())
            .unwrap_or(1);
        execute_collect_sub_chunked_scope(producer, sub_chunks, threads)
    }
}

#[cfg(target_arch = "wasm32")]
pub fn execute_fold_reduce_sub_chunked<P: FrfProducer, B, INIT, FOLD, REDUCE>(
    producer: P,
    _sub_chunks: usize,
    init: INIT,
    fold: FOLD,
    _reduce: REDUCE,
) -> B
where
    B: Send,
    INIT: Fn() -> B + Sync + Send,
    FOLD: Fn(B, P::Item) -> B + Sync + Send,
    REDUCE: Fn(B, B) -> B + Sync + Send,
{
    producer.into_iter().fold(init(), fold)
}

#[cfg(not(target_arch = "wasm32"))]
pub fn execute_fold_reduce_sub_chunked<P: FrfProducer, B, INIT, FOLD, REDUCE>(
    producer: P,
    sub_chunks: usize,
    init: INIT,
    fold: FOLD,
    reduce: REDUCE,
) -> B
where
    B: Send,
    P::Item: Send,
    INIT: Fn() -> B + Sync + Send,
    FOLD: Fn(B, P::Item) -> B + Sync + Send,
    REDUCE: Fn(B, B) -> B + Sync + Send,
{
    if crate::pool::is_in_pool() {
        return producer.into_iter().fold(init(), fold);
    }
    if let Some(pool) = crate::pool::get_pool() {
        let k = pool.k;
        if k <= 1 || producer.len() <= 1 {
            return producer.into_iter().fold(init(), fold);
        }
        let m = std::cmp::max(sub_chunks, k);
        let mini_batch_enabled = producer.len().div_ceil(m) >= STEAL_MIN_LEN;
        let mut producers = split_into_sub_chunks(producer, m);

        if !mini_batch_enabled {
            let balanced_chunks = chunks_are_balanced(&producers);
            let permutation = if balanced_chunks {
                None
            } else {
                Some(stable_execution_permutation_for_chunks(&producers))
            };
            let counter = std::sync::atomic::AtomicUsize::new(0);
            let counter_ptr = &counter as *const std::sync::atomic::AtomicUsize as usize;
            let ptr_val = producers.as_mut_ptr() as usize;
            let order_ptr = permutation
                .as_ref()
                .map_or(std::ptr::null::<usize>() as usize, |p| {
                    p.order.as_ptr() as usize
                });

            let mut results: Vec<Option<B>> = (0..k).map(|_| None).collect();
            let res_ptr_val = results.as_mut_ptr() as usize;

            crate::pool::execute_with_pool(&pool, &|index| {
                let mut acc = init();
                loop {
                    let counter =
                        unsafe { &*(counter_ptr as *const std::sync::atomic::AtomicUsize) };
                    let slot = counter.fetch_add(1, std::sync::atomic::Ordering::Relaxed);
                    if slot >= m {
                        break;
                    }
                    let idx = if order_ptr == 0 {
                        slot
                    } else {
                        unsafe { *(order_ptr as *const usize).add(slot) }
                    };
                    let p = unsafe { (*(ptr_val as *mut Option<P>).add(idx)).take().unwrap() };
                    acc = p.into_iter().fold(acc, &fold);
                }
                unsafe {
                    *(res_ptr_val as *mut Option<B>).add(index) = Some(acc);
                }
            });
            drop(permutation);
            drop(producers);

            return results
                .into_iter()
                .flatten()
                .reduce(reduce)
                .unwrap_or_else(init);
        }

        let mut cells: Vec<StealCell<P>> = (0..m).map(|_| StealCell::new()).collect();
        let mut mini_storage: Vec<Vec<std::cell::UnsafeCell<Option<P>>>> =
            (0..m).map(|_| Vec::new()).collect();

        let counter = std::sync::atomic::AtomicUsize::new(0);
        let counter_ptr = &counter as *const std::sync::atomic::AtomicUsize as usize;
        let ptr_val = producers.as_mut_ptr() as usize;
        let cells_ptr = cells.as_mut_ptr() as usize;
        let mini_storage_ptr = mini_storage.as_mut_ptr() as usize;

        let mut results: Vec<Option<B>> = (0..k).map(|_| None).collect();
        let res_ptr_val = results.as_mut_ptr() as usize;

        crate::pool::execute_with_pool(&pool, &|index| {
            let mut acc = init();
            loop {
                let counter = unsafe { &*(counter_ptr as *const std::sync::atomic::AtomicUsize) };
                let idx = counter.fetch_add(1, std::sync::atomic::Ordering::Relaxed);
                if idx >= m {
                    break;
                }
                let p_opt = unsafe { (*(ptr_val as *mut Option<P>).add(idx)).take() };
                let Some(p) = p_opt else {
                    continue;
                };
                let plen = p.len();
                if plen < STEAL_MIN_LEN {
                    acc = p.into_iter().fold(acc, &fold);
                    continue;
                }

                let mini = split_into_mini_batches(p, STEAL_MINI_BATCHES);
                let m2 = mini.len();
                let storage: &mut Vec<std::cell::UnsafeCell<Option<P>>> = unsafe {
                    &mut *(mini_storage_ptr as *mut Vec<std::cell::UnsafeCell<Option<P>>>).add(idx)
                };
                storage.reserve_exact(m2);
                for opt in mini {
                    storage.push(std::cell::UnsafeCell::new(opt));
                }
                let cell: &StealCell<P> = unsafe { &*(cells_ptr as *const StealCell<P>).add(idx) };
                cell.slots.store(
                    storage.as_mut_ptr() as *mut (),
                    std::sync::atomic::Ordering::Release,
                );
                cell.populated
                    .store(m2, std::sync::atomic::Ordering::Release);
                acc = unsafe { drain_mini_batches_reduce::<P, B, FOLD>(cell, acc, &fold) };
            }

            let central_ref = unsafe { &*(counter_ptr as *const std::sync::atomic::AtomicUsize) };
            while central_ref.load(std::sync::atomic::Ordering::Relaxed) < m {
                let mut did_work = false;
                for j in 0..m {
                    let cell: &StealCell<P> =
                        unsafe { &*(cells_ptr as *const StealCell<P>).add(j) };
                    let populated = cell.populated.load(std::sync::atomic::Ordering::Acquire);
                    if populated == 0 {
                        continue;
                    }
                    let cursor = cell.cursor.load(std::sync::atomic::Ordering::Relaxed);
                    if cursor >= populated {
                        continue;
                    }
                    acc = unsafe { drain_mini_batches_reduce::<P, B, FOLD>(cell, acc, &fold) };
                    did_work = true;
                }
                if !did_work {
                    std::hint::spin_loop();
                }
            }

            loop {
                let mut did_work = false;
                for j in 0..m {
                    let cell: &StealCell<P> =
                        unsafe { &*(cells_ptr as *const StealCell<P>).add(j) };
                    let populated = cell.populated.load(std::sync::atomic::Ordering::Acquire);
                    if populated == 0 {
                        continue;
                    }
                    let cursor = cell.cursor.load(std::sync::atomic::Ordering::Relaxed);
                    if cursor >= populated {
                        continue;
                    }
                    acc = unsafe { drain_mini_batches_reduce::<P, B, FOLD>(cell, acc, &fold) };
                    did_work = true;
                }
                if !did_work {
                    break;
                }
            }

            unsafe {
                *(res_ptr_val as *mut Option<B>).add(index) = Some(acc);
            }
        });
        drop(cells);
        drop(mini_storage);
        drop(producers);

        results
            .into_iter()
            .flatten()
            .reduce(reduce)
            .unwrap_or_else(init)
    } else {
        let threads = std::thread::available_parallelism()
            .map(|n| n.get())
            .unwrap_or(1);
        execute_fold_reduce_sub_chunked_scope(producer, sub_chunks, &init, &fold, &reduce, threads)
    }
}

#[cfg(all(test, not(target_arch = "wasm32")))]
mod tests {
    use super::*;

    #[derive(Clone)]
    struct TestProducer {
        len: usize,
    }

    impl FrfProducer for TestProducer {
        type Item = usize;
        type Iter = std::ops::Range<usize>;

        fn len(&self) -> usize {
            self.len
        }

        fn split_at(self, index: usize) -> (Self, Self) {
            (
                Self { len: index },
                Self {
                    len: self.len.saturating_sub(index),
                },
            )
        }

        fn into_iter(self) -> Self::Iter {
            0..self.len
        }
    }

    #[test]
    fn stable_chunk_execution_order_runs_larger_chunks_first_and_ties_by_slot() {
        let producers = vec![
            Some(TestProducer { len: 4 }),
            Some(TestProducer { len: 9 }),
            Some(TestProducer { len: 9 }),
            Some(TestProducer { len: 1 }),
        ];

        let permutation = stable_execution_permutation_for_chunks(&producers);

        assert_eq!(permutation.order, vec![1, 2, 0, 3]);
    }

    #[test]
    fn balanced_chunks_skip_execution_permutation_allocation() {
        let producers = vec![
            Some(TestProducer { len: 64 }),
            Some(TestProducer { len: 64 }),
            Some(TestProducer { len: 63 }),
        ];

        assert!(chunks_are_balanced(&producers));
    }

    #[test]
    fn small_bursty_loads_stay_serial_below_the_cutoff() {
        // Default cutoff is 16 (GNOSIS_FRF_SERIAL_CUTOFF unset in tests).
        let cutoff = serial_cutoff();
        assert_eq!(cutoff, 16, "default serial cutoff");
        // Below the cutoff, never parallelize regardless of core count — the
        // dispatch overhead dominates (benches/bench_small_bursty.rs).
        for total in [2usize, 4, 8, 15] {
            assert_eq!(
                compute_k_eff(total, 8),
                1,
                "total={total} below cutoff must stay serial"
            );
            assert_eq!(
                compute_k_eff(total, 64),
                1,
                "high core count must not override the cutoff"
            );
        }
        // At and above the cutoff, parallelism is allowed again.
        assert!(compute_k_eff(16, 8) >= 1);
        assert!(compute_k_eff(64, 8) >= 2, "64 elems on 8 cores parallelizes");
        // Large loads are unchanged: the grain heuristic still saturates k.
        assert_eq!(compute_k_eff(1_000_000, 8), 8);
        assert_eq!(compute_k_eff(1_000_000, 16), 16);
    }

    #[test]
    fn mini_batch_admission_exposes_cover_required_residual_mass() {
        let rejected = assess_mini_batch_admission(1_000_000, 15_625);
        assert_eq!(rejected.chunk_len, 64);
        assert_eq!(rejected.required_len, STEAL_MIN_LEN);
        assert_eq!(rejected.covered_mass, 64);
        assert_eq!(rejected.residual_mass, 32);
        assert!(!rejected.admitted);

        let admitted = assess_mini_batch_admission(1_000_000, 64);
        assert_eq!(admitted.chunk_len, 15_625);
        assert_eq!(admitted.residual_mass, 0);
        assert!(admitted.admitted);
    }
}
